const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  Header, Footer, AlignmentType, HeadingLevel, BorderStyle, WidthType,
  ShadingType, VerticalAlign, PageNumber, PageBreak, LevelFormat
} = require('docx');
const fs = require('fs');

// ─── Brand Colors ─────────────────────────────────────────────────────────────
const NAVY      = "0A1628";   // Deep navy (Breakthrough brand)
const GOLD      = "B8860B";   // Dark gold
const GOLD_LITE = "D4AF37";   // Light gold accent
const SLATE     = "2C3E50";   // Section headers
const MID_GRAY  = "546E7A";   // Body secondary
const LIGHT_BG  = "F2F4F8";   // Table row alternates
const WHITE     = "FFFFFF";
const WARN_RED  = "8B0000";   // Compliance warnings

// ─── DXA Constants (US Letter 1" margins → 9360 DXA content width) ────────────
const PAGE_W    = 12240;
const PAGE_H    = 15840;
const MARGIN    = 1440;       // 1 inch
const CONTENT_W = PAGE_W - (MARGIN * 2); // 9360 DXA

// ─── Helper: Empty paragraph spacer ──────────────────────────────────────────
const sp = (before = 0, after = 120) => new Paragraph({
  children: [new TextRun("")],
  spacing: { before, after }
});

// ─── Helper: Horizontal rule ─────────────────────────────────────────────────
const hr = (color = GOLD) => new Paragraph({
  children: [new TextRun("")],
  border: {
    bottom: { style: BorderStyle.SINGLE, size: 6, color, space: 1 }
  },
  spacing: { before: 160, after: 160 }
});

// ─── Helper: Section heading (navy bar label) ─────────────────────────────────
const sectionLabel = (text) => new Paragraph({
  children: [new TextRun({
    text: text.toUpperCase(),
    bold: true,
    color: WHITE,
    size: 20,
    font: "Arial"
  })],
  shading: { fill: NAVY, type: ShadingType.CLEAR },
  spacing: { before: 240, after: 160 },
  indent: { left: 120, right: 120 }
});

// ─── Helper: Body paragraph ───────────────────────────────────────────────────
const body = (text, opts = {}) => new Paragraph({
  children: [new TextRun({
    text,
    size: 22,
    font: "Arial",
    color: opts.color || SLATE,
    bold: opts.bold || false,
    italics: opts.italics || false
  })],
  spacing: { before: 60, after: 120 },
  alignment: opts.align || AlignmentType.LEFT
});

// ─── Helper: Key-value inline ─────────────────────────────────────────────────
const kv = (label, value, labelColor = GOLD, valueColor = SLATE) => new Paragraph({
  children: [
    new TextRun({ text: label + ": ", bold: true, size: 22, color: labelColor, font: "Arial" }),
    new TextRun({ text: value, size: 22, color: valueColor, font: "Arial" })
  ],
  spacing: { before: 60, after: 80 }
});

// ─── Helper: Build a standard table row ──────────────────────────────────────
const borderDef = { style: BorderStyle.SINGLE, size: 1, color: "DDDDDD" };
const cellBorders = {
  top: borderDef, bottom: borderDef, left: borderDef, right: borderDef
};

const tRow = (cells, isHeader = false) => new TableRow({
  tableHeader: isHeader,
  children: cells.map(({ text, width, align, shade, colspan }) =>
    new TableCell({
      columnSpan: colspan || 1,
      borders: cellBorders,
      width: { size: width || Math.floor(CONTENT_W / cells.length), type: WidthType.DXA },
      shading: { fill: shade || (isHeader ? NAVY : WHITE), type: ShadingType.CLEAR },
      margins: { top: 80, bottom: 80, left: 140, right: 140 },
      verticalAlign: VerticalAlign.CENTER,
      children: [new Paragraph({
        alignment: align || AlignmentType.LEFT,
        children: [new TextRun({
          text: String(text),
          size: 20,
          font: "Arial",
          bold: isHeader,
          color: isHeader ? WHITE : SLATE
        })]
      })]
    })
  )
});

// ─── Helper: Build a full table ───────────────────────────────────────────────
const makeTable = (headers, rows, colWidths) => {
  const totalWidth = colWidths.reduce((a, b) => a + b, 0);
  return new Table({
    width: { size: CONTENT_W, type: WidthType.DXA },
    columnWidths: colWidths,
    rows: [
      tRow(
        headers.map((h, i) => ({ text: h, width: colWidths[i] })),
        true
      ),
      ...rows.map((row, ri) =>
        tRow(
          row.map((cell, i) => ({
            text: cell,
            width: colWidths[i],
            shade: ri % 2 === 0 ? WHITE : LIGHT_BG
          }))
        )
      )
    ]
  });
};

// ─── Numbering Config ─────────────────────────────────────────────────────────
const numberingConfig = [
  {
    reference: "bullets",
    levels: [{
      level: 0,
      format: LevelFormat.BULLET,
      text: "•",
      alignment: AlignmentType.LEFT,
      style: { paragraph: { indent: { left: 720, hanging: 360 } } }
    }]
  },
  {
    reference: "check",
    levels: [{
      level: 0,
      format: LevelFormat.BULLET,
      text: "✓",
      alignment: AlignmentType.LEFT,
      style: { paragraph: { indent: { left: 720, hanging: 360 } } }
    }]
  }
];

const bullet = (text, bold = false, color = SLATE) => new Paragraph({
  numbering: { reference: "bullets", level: 0 },
  children: [new TextRun({ text, size: 22, font: "Arial", bold, color })],
  spacing: { before: 40, after: 60 }
});

const check = (text) => new Paragraph({
  numbering: { reference: "check", level: 0 },
  children: [new TextRun({ text, size: 22, font: "Arial", color: SLATE })],
  spacing: { before: 40, after: 60 }
});

// ─── Header / Footer ──────────────────────────────────────────────────────────
const docHeader = new Header({
  children: [
    new Paragraph({
      children: [
        new TextRun({ text: "CONFIDENTIAL — ACCREDITED INVESTORS ONLY  |  REG D 506(c)", size: 16, font: "Arial", color: MID_GRAY }),
        new TextRun({ text: "  |  ", size: 16, color: MID_GRAY }),
        new TextRun({ text: "MineTeck LLC | Urban Mining LLC", size: 16, bold: true, font: "Arial", color: NAVY })
      ],
      border: { bottom: { style: BorderStyle.SINGLE, size: 4, color: GOLD, space: 1 } },
      spacing: { after: 0 }
    })
  ]
});

const docFooter = new Footer({
  children: [
    new Paragraph({
      children: [
        new TextRun({ text: "This document contains forward-looking statements and is for informational purposes only. Past performance does not guarantee future results.  |  Page ", size: 16, font: "Arial", color: MID_GRAY }),
        new TextRun({ children: [PageNumber.CURRENT], size: 16, font: "Arial", color: MID_GRAY })
      ],
      border: { top: { style: BorderStyle.SINGLE, size: 4, color: GOLD, space: 1 } },
      spacing: { before: 0 }
    })
  ]
});

