const doc = new Document({
  numbering: { config: numberingConfig },
  styles: {
    default: {
      document: { run: { font: "Arial", size: 22, color: SLATE } }
    },
    paragraphStyles: [
      {
        id: "Heading1", name: "Heading 1", basedOn: "Normal", next: "Normal", quickFormat: true,
        run: { size: 32, bold: true, font: "Arial", color: NAVY },
        paragraph: { spacing: { before: 240, after: 160 }, outlineLevel: 0 }
      },
      {
        id: "Heading2", name: "Heading 2", basedOn: "Normal", next: "Normal", quickFormat: true,
        run: { size: 26, bold: true, font: "Arial", color: SLATE },
        paragraph: { spacing: { before: 160, after: 120 }, outlineLevel: 1 }
      }
    ]
  },
  sections: [
    {
      properties: {
        page: {
          size: { width: PAGE_W, height: PAGE_H },
          margin: { top: MARGIN, right: MARGIN, bottom: MARGIN, left: MARGIN }
        }
      },
      headers: { default: docHeader },
      footers: { default: docFooter },
      children: [
        ...buildCoverPage(),
        ...buildDisclaimerPage(),
        ...buildExecutiveSummary(),
        ...buildMarketOpportunity(),
        ...buildMineTeckSection(),
        ...buildUrbanMiningSection(),
        ...buildGTMStrategy(),
        ...buildUseOfFunds(),
        ...buildFinancials(),
        ...buildRiskFactors(),
        ...buildTeamPage()
      ]
    }
  ]
});

// ─── Write to file ────────────────────────────────────────────────────────────
Packer.toBuffer(doc).then(buffer => {
  const outputPath = "MineTeck_UrbanMining_Capital_Raise_Proposal.docx";
  fs.writeFileSync(outputPath, buffer);
  console.log(`\n✅ Document generated: ${outputPath}`);
  console.log(`   Size: ${(buffer.length / 1024).toFixed(1)} KB`);
  console.log(`\n   Open with Microsoft Word or LibreOffice.\n`);
}).catch(err => {
  console.error("❌ Error generating document:", err);
  process.exit(1);
});
